WITH (
    LOCATION='https://azuredwhing.dfs.core.windows.net/silver/',
    CREDENTIAL=POOJA_CREDS
);


-------------EXTERNAL DATA SOURCE GOLD--------------
CREATE EXTERNAL DATA SOURCE GOLD_SOURCE
WITH (
    LOCATION='https://azuredwhing.dfs.core.windows.net/gold/',
    CREDENTIAL=POOJA_CREDS
);


-------------EXTERNAL FILE FORMAT--------------
-----1-----PARQUET FORMAT----------
